<?php
declare(strict_types=1);

session_start();
date_default_timezone_set('Europe/London');

$root = dirname(__DIR__);
$configFile = $root . '/config/app.php';
$sqlFile = $root . '/rook_chat.sql';
require_once $root . '/lib/ai_providers.php';

function e(string $v): string { return htmlspecialchars($v, ENT_QUOTES, 'UTF-8'); }
function is_post(): bool { return ($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST'; }
function base_path(): string {
    $script = str_replace('\\', '/', (string)($_SERVER['SCRIPT_NAME'] ?? '/install/index.php'));
    $pos = strpos($script, '/install/');
    $base = $pos === false ? rtrim(dirname(dirname($script)), '/') : substr($script, 0, $pos);
    return $base === '/' ? '' : rtrim($base, '/');
}
function redirect_step(int $step): never { header('Location: ' . base_path() . '/install/?step=' . $step); exit; }
function state(): array { return $_SESSION['rook_install'] ?? []; }
function save_state(array $data): void { $_SESSION['rook_install'] = array_replace(state(), $data); }
function php_config(array $s): string {
    $export = fn($v) => var_export((string)$v, true);
    return "<?php\n" .
        "// Generated by the RookGPT installer on " . date('c') . ".\n" .
        "defined('DB_HOST') || define('DB_HOST', " . $export($s['db_host'] ?? '127.0.0.1') . ");\n" .
        "defined('DB_NAME') || define('DB_NAME', " . $export($s['db_name'] ?? 'rook_chat') . ");\n" .
        "defined('DB_USER') || define('DB_USER', " . $export($s['db_user'] ?? '') . ");\n" .
        "defined('DB_PASS') || define('DB_PASS', " . $export($s['db_pass'] ?? '') . ");\n" .
        "defined('AI_PROVIDER') || define('AI_PROVIDER', " . $export($s['ai_provider'] ?? 'ollama') . ");\n" .
        "defined('AI_BASE_URL') || define('AI_BASE_URL', " . $export($s['ai_base_url'] ?? 'http://127.0.0.1:11434/api/chat') . ");\n" .
        "defined('AI_MODEL') || define('AI_MODEL', " . $export($s['ai_model'] ?? 'gemma4:e4b') . ");\n" .
        "defined('AI_API_KEY') || define('AI_API_KEY', " . $export($s['ai_api_key'] ?? '') . ");\n" .
        "defined('OLLAMA_URL') || define('OLLAMA_URL', AI_BASE_URL);\n" .
        "defined('OLLAMA_MODEL') || define('OLLAMA_MODEL', AI_MODEL);\n" .
        "defined('STRIPE_SECRET_KEY') || define('STRIPE_SECRET_KEY', " . $export($s['stripe_secret_key'] ?? '') . ");\n" .
        "defined('TEAM_CHAT_ENCRYPTION_KEY') || define('TEAM_CHAT_ENCRYPTION_KEY', " . $export($s['team_chat_encryption_key'] ?? bin2hex(random_bytes(32))) . ");\n" .
        "defined('TEAMS_REQUIRE_2FA') || define('TEAMS_REQUIRE_2FA', true);\n" .
        "defined('APP_NAME') || define('APP_NAME', 'RookGPT');\n" .
        "defined('APP_TAGLINE') || define('APP_TAGLINE', 'Professional AI assistant');\n" .
        "defined('PLAN_PLUS_PRICE_GBP') || define('PLAN_PLUS_PRICE_GBP', 9.00);\n" .
        "defined('PLAN_PRO_PRICE_GBP') || define('PLAN_PRO_PRICE_GBP', 19.00);\n" .
        "defined('PLAN_BUSINESS_PRICE_GBP') || define('PLAN_BUSINESS_PRICE_GBP', 49.00);\n" .
        "defined('ANNUAL_DISCOUNT_MONTHS') || define('ANNUAL_DISCOUNT_MONTHS', 2);\n" .
        "defined('ROOK_PLAN_DEFINITIONS') || define('ROOK_PLAN_DEFINITIONS', []);\n";
}
function split_sql(string $sql): array {
    $sql = preg_replace('/^\s*CREATE\s+DATABASE\b.*?;\s*/mi', '', $sql) ?? $sql;
    $sql = preg_replace('/^\s*USE\s+`?[^`;]+`?\s*;\s*/mi', '', $sql) ?? $sql;
    $parts = [];
    $buf = ''; $inString = false; $quote = '';
    $len = strlen($sql);
    for ($i=0; $i<$len; $i++) {
        $ch = $sql[$i]; $buf .= $ch;
        if ($inString) {
            if ($ch === $quote && ($i === 0 || $sql[$i-1] !== '\\')) $inString = false;
        } elseif ($ch === "'" || $ch === '"') { $inString = true; $quote = $ch; }
        elseif ($ch === ';') { $stmt = trim($buf); if ($stmt !== '') $parts[] = $stmt; $buf = ''; }
    }
    $tail = trim($buf); if ($tail !== '') $parts[] = $tail;
    return $parts;
}
function install_schema_and_admin(array $s): int {
    global $sqlFile;
    mysqli_report(MYSQLI_REPORT_ERROR | MYSQLI_REPORT_STRICT);
    $server = new mysqli($s['db_host'], $s['db_user'], $s['db_pass']);
    $dbName = preg_replace('/[^a-zA-Z0-9_\-]/', '', (string)$s['db_name']);
    if ($dbName === '') throw new RuntimeException('Invalid database name.');
    $server->query("CREATE DATABASE IF NOT EXISTS `" . $server->real_escape_string($dbName) . "` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci");
    $server->select_db($dbName);
    $server->set_charset('utf8mb4');
    if (!is_file($sqlFile)) throw new RuntimeException('Missing rook_chat.sql.');
    foreach (split_sql(file_get_contents($sqlFile) ?: '') as $stmt) {
        if (trim($stmt) !== '') $server->query($stmt);
    }
    $hash = password_hash($s['admin_password'], PASSWORD_DEFAULT);
    $stmt = $server->prepare("INSERT INTO users (username,email,password_hash,plan,plan_billing_period,thinking_enabled) VALUES (?,?,?,?,?,1) ON DUPLICATE KEY UPDATE password_hash=VALUES(password_hash), plan='business', plan_billing_period='manual'");
    $username=$s['admin_username']; $email=$s['admin_email']; $plan='business'; $period='manual';
    $stmt->bind_param('sssss', $username, $email, $hash, $plan, $period); $stmt->execute(); $stmt->close();
    $userId = (int)$server->insert_id;
    if ($userId <= 0) { $q=$server->prepare('SELECT id FROM users WHERE email=? LIMIT 1'); $q->bind_param('s',$email); $q->execute(); $row=$q->get_result()->fetch_assoc(); $userId=(int)($row['id']??0); $q->close(); }
    if ($userId <= 0) throw new RuntimeException('Could not create admin account.');
    $stmt=$server->prepare("INSERT INTO admins (user_id,role,is_active) VALUES (?,'owner',1) ON DUPLICATE KEY UPDATE role='owner', is_active=1");
    $stmt->bind_param('i',$userId); $stmt->execute(); $stmt->close();
    $server->close();
    return $userId;
}
function sign_in_installed_admin(array $s, int $userId): void {
    mysqli_report(MYSQLI_REPORT_ERROR | MYSQLI_REPORT_STRICT);
    session_regenerate_id(true);
    $token = bin2hex(random_bytes(32));
    $dbName = preg_replace('/[^a-zA-Z0-9_\-]/', '', (string)$s['db_name']);
    $db = new mysqli($s['db_host'], $s['db_user'], $s['db_pass'], $dbName);
    $db->set_charset('utf8mb4');
    $stmt = $db->prepare('UPDATE users SET current_session_token = ?, session_rotated_at = NOW() WHERE id = ?');
    $stmt->bind_param('si', $token, $userId);
    $stmt->execute();
    $stmt->close();
    $db->close();
    unset($_SESSION['pending_2fa_user_id'], $_SESSION['pending_2fa_started_at'], $_SESSION['pending_2fa_secret']);
    $_SESSION['user_id'] = $userId;
    $_SESSION['session_token'] = $token;
    $_SESSION['flash'] = 'Install complete. You are signed in as the owner admin.';
}

$step = max(1, min(6, (int)($_GET['step'] ?? 1)));
$errors = [];
if (is_file($configFile) && $step < 6) $step = 6;

if (is_post()) {
    try {
        if ($step === 1) redirect_step(2);
        if ($step === 2) {
            $data = [
                'db_host' => trim((string)($_POST['db_host'] ?? '127.0.0.1')),
                'db_name' => trim((string)($_POST['db_name'] ?? 'rook_chat')),
                'db_user' => trim((string)($_POST['db_user'] ?? '')),
                'db_pass' => (string)($_POST['db_pass'] ?? ''),
            ];
            if ($data['db_host']==='' || $data['db_name']==='' || $data['db_user']==='') throw new RuntimeException('Database host, name and user are required.');
            mysqli_report(MYSQLI_REPORT_ERROR | MYSQLI_REPORT_STRICT);
            $test = new mysqli($data['db_host'], $data['db_user'], $data['db_pass']); $test->close();
            save_state($data); redirect_step(3);
        }
        if ($step === 3) {
            $providers = rook_ai_providers();
            $provider = strtolower(trim((string)($_POST['ai_provider'] ?? 'ollama')));
            if (!isset($providers[$provider])) throw new RuntimeException('Choose a supported AI provider.');
            $defaults = $providers[$provider];
            $url = trim((string)($_POST['ai_base_url'] ?? $defaults['endpoint']));
            $model = trim((string)($_POST['ai_model'] ?? $defaults['model']));
            $apiKey = trim((string)($_POST['ai_api_key'] ?? ''));
            if ($url === '' || !preg_match('#^https?://#i', $url)) throw new RuntimeException('Enter a valid AI API endpoint URL.');
            if ($model === '') throw new RuntimeException('Enter an AI model name.');
            if (!empty($defaults['needs_key']) && $apiKey === '') throw new RuntimeException($defaults['name'] . ' needs an API key.');
            save_state(['ai_provider'=>$provider, 'ai_base_url'=>$url, 'ai_model'=>$model, 'ai_api_key'=>$apiKey]); redirect_step(4);
        }
        if ($step === 4) {
            $pw=(string)($_POST['admin_password'] ?? ''); $pw2=(string)($_POST['admin_password_confirm'] ?? '');
            if ($pw === '' || strlen($pw) < 8) throw new RuntimeException('Admin password must be at least 8 characters.');
            if ($pw !== $pw2) throw new RuntimeException('Passwords do not match.');
            save_state([
                'admin_username'=>trim((string)($_POST['admin_username'] ?? 'admin')),
                'admin_email'=>trim((string)($_POST['admin_email'] ?? '')),
                'admin_password'=>$pw,
            ]);
            if (!filter_var(state()['admin_email'] ?? '', FILTER_VALIDATE_EMAIL)) throw new RuntimeException('Enter a valid admin email.');
            redirect_step(5);
        }
        if ($step === 5) {
            save_state(['stripe_secret_key'=>trim((string)($_POST['stripe_secret_key'] ?? ''))]);
            $s = state();
            $adminUserId = install_schema_and_admin($s);
            $config = php_config($s);
            if (!is_dir($root . '/config')) mkdir($root . '/config', 0755, true);
            if (file_put_contents($configFile, $config, LOCK_EX) === false) throw new RuntimeException('Could not write config/app.php. Check folder permissions.');
            unset($_SESSION['rook_install']);
            sign_in_installed_admin($s, $adminUserId);
            redirect_step(6);
        }
    } catch (Throwable $e) { $errors[] = $e->getMessage(); }
}
$s = state();
$labels = [1=>'Welcome',2=>'DB Info',3=>'AI Provider',4=>'Admin Account',5=>'Stripe API Key',6=>'Finished'];
$progress = (int) round(($step / 6) * 100);
$base = base_path();
