            <div class="eyebrow">AI provider</div><h2 style="font-weight:950;letter-spacing:-.04em;">Choose how RookGPT talks to AI</h2><p class="muted">Pick one of the top AI services, or keep Ollama for a local/self-hosted setup. You can change this later from admin settings.</p>
            <form method="post" id="aiProviderForm">
              <div class="field"><label for="ai_provider">Provider</label><select id="ai_provider" name="ai_provider" required><?php foreach ($providers as $key => $provider): ?><option value="<?= e($key) ?>" data-endpoint="<?= e($provider['endpoint']) ?>" data-model="<?= e($provider['model']) ?>" data-needs-key="<?= !empty($provider['needs_key']) ? '1' : '0' ?>" <?= $selectedProvider === $key ? 'selected' : '' ?>><?= e($provider['name']) ?></option><?php endforeach; ?></select></div>
              <div class="field"><label for="ai_base_url">API endpoint</label><input id="ai_base_url" name="ai_base_url" value="<?= e($s['ai_base_url'] ?? $selectedDefaults['endpoint']) ?>" required></div>
              <div class="field"><label for="ai_api_key">API key</label><input id="ai_api_key" type="password" name="ai_api_key" value="<?= e($s['ai_api_key'] ?? '') ?>" placeholder="Leave blank for Ollama/local providers"></div>
              <div class="field"><label for="ai_model">Model</label><select id="ai_model" name="ai_model" required data-current="<?= e($s['ai_model'] ?? $selectedDefaults['model']) ?>"><option value="<?= e($s['ai_model'] ?? $selectedDefaults['model']) ?>" selected><?= e($s['ai_model'] ?? $selectedDefaults['model']) ?></option></select></div>
              <div class="notice"><i class="fa-solid fa-lightbulb me-2"></i><span id="aiProviderHint"><?= e($selectedDefaults['note']) ?></span></div>
              <div class="action-row"><button class="btn-ghost" type="button" id="fetchModelsBtn"><i class="fa-solid fa-cloud-arrow-down"></i> Test key & fetch models</button><button class="btn-rook"><i class="fa-solid fa-arrow-right"></i> Continue</button></div>
              <div class="notice" id="modelFetchStatus" style="display:none;"></div>
            </form>
            <script>
              (() => {
                const provider = document.getElementById('ai_provider');
                const endpoint = document.getElementById('ai_base_url');
                const model = document.getElementById('ai_model');
                const key = document.getElementById('ai_api_key');
                const hint = document.getElementById('aiProviderHint');
                const btn = document.getElementById('fetchModelsBtn');
                const status = document.getElementById('modelFetchStatus');
                const notes = <?= json_encode(array_map(fn($p) => $p['note'], rook_ai_providers()), JSON_UNESCAPED_SLASHES | JSON_UNESCAPED_UNICODE) ?>;
                function showStatus(message, ok = true) { if (!status) return; status.style.display = 'block'; status.innerHTML = '<i class="fa-solid ' + (ok ? 'fa-circle-check' : 'fa-triangle-exclamation') + ' me-2"></i>' + message; status.classList.toggle('danger', !ok); }
                function setModelOptions(models, preferred = '') {
                  const keep = preferred || model.value || model.dataset.current || '';
                  model.innerHTML = '';
                  const list = Array.from(new Set((models || []).filter(Boolean)));
                  if (keep && !list.includes(keep)) list.unshift(keep);
                  if (!list.length) list.push('');
                  list.forEach((name) => {
                    const option = document.createElement('option');
                    option.value = name;
                    option.textContent = name || 'Select a model';
                    model.appendChild(option);
                  });
                  model.value = list.includes(keep) ? keep : list[0];
                  model.dataset.current = model.value;
                }
                function fillModels(models) {
                  const autoPick = (!model.value || model.dataset.auto === '1');
                  setModelOptions(models, autoPick ? ((models || [])[0] || model.value) : model.value);
                  if ((models || []).length && autoPick) model.dataset.auto = '1';
                }
                provider?.addEventListener('change', () => { const opt = provider.options[provider.selectedIndex]; endpoint.value = opt.dataset.endpoint || endpoint.value; setModelOptions([opt.dataset.model || model.value], opt.dataset.model || model.value); model.dataset.auto = '1'; key.placeholder = opt.dataset.needsKey === '1' ? 'Required for this provider' : 'Leave blank for Ollama/local providers'; hint.textContent = notes[provider.value] || ''; if (status) status.style.display = 'none'; });
                model?.addEventListener('change', () => { model.dataset.auto = '0'; model.dataset.current = model.value; });
                async function fetchModels(silent = false) {
                  if (!silent) { btn.disabled = true; btn.dataset.original = btn.innerHTML; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Checking provider...'; }
                  try {
                    const body = new URLSearchParams({provider: provider.value, endpoint: endpoint.value, api_key: key.value});
                    const res = await fetch('models', {method:'POST', headers:{'Content-Type':'application/x-www-form-urlencoded'}, body});
                    const data = await res.json();
                    if (!res.ok || !data.ok) throw new Error(data.error || 'Could not fetch models.');
                    fillModels(data.models || []);
                    showStatus('Connected successfully. Loaded ' + (data.models || []).length + ' model' + ((data.models || []).length === 1 ? '' : 's') + '.');
                  } catch (err) { if (!silent) showStatus(err.message || 'Could not fetch models.', false); }
                  finally { if (!silent) { btn.disabled = false; btn.innerHTML = btn.dataset.original || '<i class="fa-solid fa-cloud-arrow-down"></i> Test key & fetch models'; } }
                }
                function canAutoFetch() { const opt = provider.options[provider.selectedIndex]; return endpoint.value && (opt.dataset.needsKey !== '1' || key.value.trim().length > 8); }
                btn?.addEventListener('click', () => fetchModels(false));
                key?.addEventListener('blur', () => { if (canAutoFetch()) fetchModels(false); });
                endpoint?.addEventListener('blur', () => { if (canAutoFetch()) fetchModels(false); });
                provider?.addEventListener('change', () => { setTimeout(() => { if (canAutoFetch()) fetchModels(true); }, 50); });
              })();
            </script>          <?php elseif($step===4): ?>
            <div class="eyebrow">Owner account</div><h2 style="font-weight:950;letter-spacing:-.04em;">Create the first admin</h2><p class="muted">This user gets Business access and owner permissions for the admin area.</p><form method="post"><div class="form-grid"><div class="field"><label for="admin_username">Username</label><input id="admin_username" name="admin_username" value="<?= e($s['admin_username'] ?? 'admin') ?>" required></div><div class="field"><label for="admin_email">Email</label><input id="admin_email" type="email" name="admin_email" placeholder="admin@example.com" value="<?= e($s['admin_email'] ?? '') ?>" required></div><div class="field"><label for="admin_password">Password</label><input id="admin_password" type="password" name="admin_password" placeholder="Minimum 8 characters" required></div><div class="field"><label for="admin_password_confirm">Confirm password</label><input id="admin_password_confirm" type="password" name="admin_password_confirm" placeholder="Repeat password" required></div></div><div class="action-row"><button class="btn-rook"><i class="fa-solid fa-user-shield"></i> Continue</button></div></form>
          <?php elseif($step===5): ?>
            <div class="eyebrow">Payments</div><h2 style="font-weight:950;letter-spacing:-.04em;">Add Stripe now, or skip it</h2><p class="muted">Stripe is optional during setup. Leave it blank and configure it later in <strong>/admin/settings</strong>.</p><form method="post"><div class="field"><label for="stripe_secret_key">Stripe secret key</label><input id="stripe_secret_key" type="password" name="stripe_secret_key" placeholder="sk_test_... or sk_live_..." value="<?= e($s['stripe_secret_key'] ?? '') ?>"></div><div class="action-row"><button class="btn-rook"><i class="fa-solid fa-flag-checkered"></i> Finish install</button><button class="btn-ghost" type="submit"><i class="fa-solid fa-forward"></i> Skip and finish</button></div></form>
          <?php else: ?>
            <div class="finish-icon"><i class="fa-solid fa-check"></i></div><div class="eyebrow">Finished</div><h2 style="font-weight:950;letter-spacing:-.04em;">RookGPT is ready</h2><div class="finish-card"><strong>Important security step</strong><p class="muted mb-0 mt-1">You are now signed in as the owner admin. Delete the <strong>/install/</strong> directory from your server before opening the app. Then click OK to continue.</p></div><div class="action-row"><a class="btn-rook" href="<?= e($base ?: '/') ?>"><i class="fa-solid fa-check"></i> OK, open RookGPT</a><a class="btn-ghost" href="<?= e($base) ?>/admin/"><i class="fa-solid fa-shield-halved"></i> Open admin</a></div>
          <?php endif; ?>
        </section>
      </section>
    </div>
  </main>
</div>
